# phase5-skills-section-config.ps1
# Reusability Phase 5: fully configurable Skills section — title/subtitle/description,
# visibility, homepage position, layout (grid/cards/compact), background (default/
# transparent/gradient/image), category & skill CRUD with reorder/visibility/featured/icon.
$ErrorActionPreference = 'Stop'
Write-Host "Applying Phase 5: Skills Section Configuration..." -ForegroundColor Cyan

Write-Host "Writing prisma\schema.prisma"
$dir = Split-Path -Parent "prisma\schema.prisma"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64Schema = @"

"@
